async function carregarPlanosCliente(){let c=document.getElementById('planosClienteContainer');if(!c)return;let bid=sessionStorage.getItem('barbeiroId');if(!bid)return;try{let sn=await db.collection('planos').where('barbeiroId','==',bid).get();let p=sn.docs.map(d=>({id:d.id,...d.data()}));c.innerHTML=p.length===0?'<p style="color:#6B7280;">Nenhum plano</p>':p.map(x=>'<div class="plano-card"><div class="plano-info"><div class="plano-nome">'+x.nome+'</div><div class="plano-periodo">📅 '+x.periodo+'</div></div><div class="plano-preco">R$ '+(x.preco||0).toFixed(2)+'</div></div>').join('');}catch(e){}}
async function criarPlano(){if(!barbeiroLogado)return;let n=document.getElementById('planoNome').value.trim(),p=document.getElementById('planoPeriodo').value,pr=parseFloat(document.getElementById('planoPreco').value);if(!n||!pr){mostrarToast('❌ Preencha!','error');return;}try{await db.collection('planos').add({barbeiroId:barbeiroLogado.id,nome:n,periodo:p,preco:pr,dataCriacao:new Date().toISOString()});mostrarToast('✅ Plano criado!','success');document.getElementById('planoNome').value='';document.getElementById('planoPreco').value='';mostrarTela('homeBarbeiro');}catch(e){}}

// ==========================================================
// POSTS DO BARBEIRO
// ==========================================================
function previewImagemPost(event){let f=event.target.files[0];if(!f)return;let r=new FileReader();r.onload=function(ev){document.getElementById('postImagem').value=ev.target.result;document.getElementById('imagemPreviewImg').src=ev.target.result;document.getElementById('imagemPreview').style.display='block';document.getElementById('imagemUploadArea').style.display='none';};r.readAsDataURL(f);}
function removerImagemPost(){document.getElementById('postImagem').value='';document.getElementById('imagemPreview').style.display='none';document.getElementById('imagemUploadArea').style.display='block';document.getElementById('postImagemInput').value='';}
async function criarPost(){if(!barbeiroLogado)return;let t=document.getElementById('postTitulo').value.trim(),p=parseFloat(document.getElementById('postPreco').value),i=document.getElementById('postImagem').value||'';if(!t||!p){mostrarToast('❌ Título e preço!','error');return;}try{let id=Date.now().toString();await db.collection('posts').doc(id).set({id,barbeiroId:barbeiroLogado.id,barbeiroNome:barbeiroLogado.nome,titulo:t,preco:p,imagem:i,likes:0,comentarios:[],dataCriacao:new Date().toISOString()});mostrarToast('✅ Publicado!','success');document.getElementById('postTitulo').value='';document.getElementById('postPreco').value='';removerImagemPost();mostrarTela('homeBarbeiro');}catch(e){}}
async function carregarMeusPosts(){let c=document.getElementById('meusPostsContainer');if(!c||!barbeiroLogado)return;try{let sn=await db.collection('posts').where('barbeiroId','==',barbeiroLogado.id).get();let posts=[];sn.forEach(d=>posts.push({id:d.id,...d.data()}));posts.sort((a,b)=>new Date(b.dataCriacao)-new Date(a.dataCriacao));c.innerHTML=posts.length===0?'<p style="color:#6B7280;">Nenhum post</p>':posts.map(p=>'<div class="feed-post" style="margin-bottom:12px;"><div class="feed-post-header"><div class="feed-post-avatar">✂️</div><div class="feed-post-user"><div class="feed-post-user-name">'+p.titulo+'</div><div class="feed-post-user-time">R$ '+(p.preco||0).toFixed(2)+'</div></div></div>'+(p.imagem?'<img src="'+p.imagem+'" class="feed-post-image">':'')+'<button class="btn btn-small btn-danger" onclick="excluirMeuPost(\''+p.id+'\')">🗑</button></div>').join('');}catch(e){}}
async function excluirMeuPost(id){if(!confirm('Excluir?'))return;await db.collection('posts').doc(id).delete();mostrarToast('🗑 Excluído!','success');carregarMeusPosts();}

// ==========================================================
// FATURAMENTO / EXTRATO
// ==========================================================
async function calcularFaturamento(){if(!barbeiroLogado)return;try{let sn=await db.collection('agendamentos').where('barbeiroId','==',barbeiroLogado.id).where('status','in',['confirmado','concluido']).get();let ag=sn.docs.map(d=>d.data()),hoje=new Date().toISOString().split('T')[0],th=0,tg=0;ag.forEach(a=>{let v=35;if(a.data===hoje)th+=v;tg+=v;});document.getElementById('faturamentoHoje').textContent='R$ '+th.toFixed(2);document.getElementById('faturamentoSemana').textContent='R$ '+(tg*0.3).toFixed(2);document.getElementById('faturamentoMes').textContent='R$ '+(tg*0.7).toFixed(2);document.getElementById('faturamentoAno').textContent='R$ '+tg.toFixed(2);}catch(e){}}
async function filtrarExtrato(periodo){calcularExtrato(periodo);}
async function calcularExtrato(periodo){let c=document.getElementById('extratoContainer');if(!c||!barbeiroLogado)return;try{let sn=await db.collection('agendamentos').where('barbeiroId','==',barbeiroLogado.id).where('status','in',['confirmado','concluido']).get();let ag=sn.docs.map(d=>d.data()),hoje=new Date(),total=0,itens=[];ag.forEach(a=>{let da=new Date(a.data),v=35,inc=!1;if(periodo==='hoje')inc=a.data===hoje.toISOString().split('T')[0];else if(periodo==='semana'){let ini=new Date(hoje);ini.setDate(hoje.getDate()-hoje.getDay());inc=da>=ini;}else if(periodo==='mes')inc=da.getMonth()===hoje.getMonth()&&da.getFullYear()===hoje.getFullYear();else if(periodo==='ano')inc=da.getFullYear()===hoje.getFullYear();else inc=!0;if(inc){total+=v;itens.push(a);}});c.innerHTML=itens.length===0?'<p style="color:#6B7280;">Nenhum</p>':'<p style="color:#D4A84B;">Total: <strong>R$ '+total.toFixed(2)+'</strong> ('+itens.length+' cortes)</p>'+itens.map(a=>'<div style="padding:8px;margin:2px 0;background:rgba(255,255,255,.03);border-radius:6px;font-size:12px;">👤 '+a.clienteNome+' • ✂️ '+a.tipo+' • 📅 '+a.data+' • R$ 35,00</div>').join('');}catch(e){}}

// ==========================================================
// LIVE
// ==========================================================
function carregarLiveTela(){let ctrl=document.getElementById('liveControlsCard');let ph=document.getElementById('livePlaceholder');if(barbeiroLogado){if(ctrl)ctrl.style.display='none';if(!liveAtiva&&ph)ph.style.display='flex';}else if(clienteLogado){if(ctrl)ctrl.style.display='none';if(liveAtivaGeral){if(ph)ph.style.display='none';document.getElementById('liveStatus').style.display='block';iniciarVisualizacaoCliente();}else{if(ph)ph.style.display='flex';document.getElementById('liveStatus').style.display='none';}}verificarLiveBadge();}
async function iniciarLive(){if(!barbeiroLogado){mostrarToast('❌ Apenas barbeiros!','error');return;}try{let s=await navigator.mediaDevices.getUserMedia({video:{width:{ideal:640},height:{ideal:480},facingMode:liveFacingMode},audio:!0});liveStreamLocal=s;liveStream=s;liveAtiva=!0;liveAtivaGeral=!0;let v=document.getElementById('liveVideo');v.srcObject=s;v.muted=!0;v.style.display='block';document.getElementById('livePlaceholder').style.display='none';document.getElementById('liveControlsCard').style.display='block';document.getElementById('liveStatus').style.display='block';liveDuracao=0;if(liveTimerInterval)clearInterval(liveTimerInterval);liveTimerInterval=setInterval(()=>{liveDuracao++;let h=Math.floor(liveDuracao/3600),m=Math.floor((liveDuracao%3600)/60),se=liveDuracao%60;document.getElementById('liveDuration').textContent=String(h).padStart(2,'0')+':'+String(m).padStart(2,'0')+':'+String(se).padStart(2,'0');},1000);await db.collection('lives').doc('live_atual').set({id:'live_atual',titulo:'Live '+barbeiroLogado.nome,barbeiroNome:barbeiroLogado.nome,ativa:!0,chat:[],viewers:0,likes:0,sorteioAtivo:!1,premioSorteio:'',participantesSorteio:[],dataInicio:new Date().toISOString()});iniciarCapturaFrames();iniciarChatListenerLive();mostrarToast('🔴 Live iniciada!','success');}catch(er){mostrarToast('❌ '+er.message,'error');}}
function iniciarCapturaFrames(){if(liveFrameInterval)clearInterval(liveFrameInterval);let canvas=document.createElement('canvas');canvas.width=320;canvas.height=180;let ctx=canvas.getContext('2d');liveFrameInterval=setInterval(async()=>{if(!liveAtiva||!liveStreamLocal)return;try{let v=document.getElementById('liveVideo');if(!v||v.videoWidth===0)return;ctx.drawImage(v,0,0,320,180);let frame=canvas.toDataURL('image/jpeg',0.5);await db.collection('lives').doc('live_atual').update({ultimoFrame:frame});}catch(e){}},1500);}
function iniciarVisualizacaoCliente(){let old=document.getElementById('liveFrameImg');if(old)old.remove();let img=document.createElement('img');img.id='liveFrameImg';img.style.cssText='position:absolute;top:0;left:0;width:100%;height:100%;object-fit:cover;z-index:1;';document.getElementById('livePlayerContainer').querySelector('div').appendChild(img);let interval=setInterval(async()=>{try{let doc=await db.collection('lives').doc('live_atual').get();if(!doc.exists||!doc.data().ativa){clearInterval(interval);img.remove();document.getElementById('livePlaceholder').style.display='flex';document.getElementById('liveStatus').style.display='none';liveAtivaGeral=!1;return;}let frame=doc.data().ultimoFrame;if(frame&&img)img.src=frame;document.getElementById('liveViewerCount').textContent='👥 '+(doc.data().viewers||0);document.getElementById('liveLikeCount').textContent=doc.data().likes||0;}catch(e){}},1500);db.collection('lives').doc('live_atual').update({viewers:firebase.firestore.FieldValue.increment(1)});iniciarChatListenerLive();}
function iniciarChatListenerLive(){if(liveChatListener)liveChatListener();liveChatListener=db.collection('lives').doc('live_atual').onSnapshot((doc)=>{if(!doc.exists||!doc.data().ativa)return;let data=doc.data(),chat=data.chat||[],c=document.getElementById('liveChatMessages');if(!c)return;let html='';if(data.sorteioAtivo){let p=data.participantesSorteio||[];html+='<div style="background:rgba(255,215,0,0.2);padding:14px;border-radius:12px;margin:8px 0;border:2px solid #FFD700;text-align:center;align-self:stretch;"><div style="font-size:24px;">🎉</div><strong style="color:#FFD700;font-size:16px;">SORTEIO ATIVO!</strong><br><span style="color:white;font-size:14px;">Prêmio: '+data.premioSorteio+'</span><br><span style="font-size:11px;color:#FFD700;">Digite <b>!PARTICIPAR</b></span><br><span style="font-size:14px;color:#fff;">👥 <b>'+p.length+'</b> participantes</span></div>';}chat.forEach(m=>{let isSent=m.autor===clienteLogado?.nome||m.autor==='✂️ '+barbeiroLogado?.nome;let cls=isSent?'sent':'received';let time=m.data?new Date(m.data).toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}):'';if(m.audio)html+='<div class="chat-bubble '+cls+' audio-bubble">'+(!isSent?'<div class="msg-sender">'+m.autor+'</div>':'')+'<audio controls src="'+m.audio+'" style="height:30px;width:160px;"></audio><span class="msg-time">🎤 '+time+'</span></div>';else html+='<div class="chat-bubble '+cls+'">'+(!isSent?'<div class="msg-sender">'+m.autor+'</div>':'')+m.texto+'<div class="msg-time">'+time+'</div></div>';});c.innerHTML=html||'<p style="color:#aaa;text-align:center;">💬 Chat vazio</p>';c.scrollTop=c.scrollHeight;});}

// ENVIAR CHAT COM SUPORTE A SORTEIO
async function enviarChatLive(){
    let i=document.getElementById('liveChatInput');if(!i)return;
    let msg=i.value.trim();if(!msg)return;
    let nome=clienteLogado?clienteLogado.nome:(barbeiroLogado?barbeiroLogado.nome:'Visitante');
    try{await db.collection('lives').doc('live_atual').update({chat:firebase.firestore.FieldValue.arrayUnion({autor:nome,texto:msg,data:new Date().toISOString()})});i.value='';
    let mu=msg.toUpperCase().trim();
    if(mu==='!PARTICIPAR'||mu==='PARTICIPAR'||mu==='QUERO PARTICIPAR'||mu==='!PARTICIPAR!'||mu==='/PARTICIPAR'){await participarSorteioLive(nome);}
    }catch(e){}
}

// PARTICIPAR SORTEIO
async function participarSorteioLive(nome){
    try{let doc=await db.collection('lives').doc('live_atual').get();if(!doc.exists||!doc.data().sorteioAtivo){mostrarToast('⚠️ Nenhum sorteio ativo!','info');return;}
    let p=doc.data().participantesSorteio||[];if(p.includes(nome)){mostrarToast('⚠️ Você já está participando!','info');return;}
    p.push(nome);await db.collection('lives').doc('live_atual').update({participantesSorteio:p});mostrarToast('✅ '+nome+' entrou! ('+p.length+'👥)','success');}catch(e){}
}

// INICIAR SORTEIO
async function iniciarSorteio(premio){if(!barbeiroLogado)return;if(!premio)premio=document.getElementById('premioSorteioInput').value.trim()||'Corte Grátis';
    try{await db.collection('lives').doc('live_atual').update({sorteioAtivo:!0,premioSorteio:premio,participantesSorteio:[],chat:firebase.firestore.FieldValue.arrayUnion({autor:'🎉 SORTEIO',texto:'SORTEIO INICIADO! Prêmio: '+premio+' | Digite !PARTICIPAR',data:new Date().toISOString()})});mostrarToast('🎉 Sorteio iniciado!','success');}catch(e){}}

// REALIZAR SORTEIO
async function realizarSorteio(){if(!barbeiroLogado)return;
    try{let doc=await db.collection('lives').doc('live_atual').get();if(!doc.exists)return;
    let data=doc.data(),p=data.participantesSorteio||[],premio=data.premioSorteio||'Corte Grátis';
    if(p.length===0){mostrarToast('❌ Ninguém participou!','error');return;}
    let v=p[Math.floor(Math.random()*p.length)];
    await db.collection('lives').doc('live_atual').update({chat:firebase.firestore.FieldValue.arrayUnion({autor:'🏆 RESULTADO',texto:'🎉 VENCEDOR: '+v+'! Prêmio: '+premio+' | Parabéns! 🎉',data:new Date().toISOString()}),sorteioAtivo:!1,participantesSorteio:[]});mostrarToast('🏆 '+v+' venceu!','success');}catch(e){}}

async function verificarLiveBadge(){try{let doc=await db.collection('lives').doc('live_atual').get();liveAtivaGeral=doc.exists&&doc.data().ativa;let bc=document.getElementById('liveBadgeCliente');if(bc)bc.style.display=liveAtivaGeral?'inline-block':'none';}catch(e){}}
async function pararLive(){if(anuncioAutoAtivo)pararAnuncioAutomatico();if(gravandoTrecho)pararGravacaoTrecho();if(liveTimerInterval)clearInterval(liveTimerInterval);if(liveFrameInterval)clearInterval(liveFrameInterval);if(liveChatListener)liveChatListener();if(liveStreamLocal)liveStreamLocal.getTracks().forEach(t=>t.stop());liveStream=null;liveStreamLocal=null;liveAtiva=!1;liveAtivaGeral=!1;let v=document.getElementById('liveVideo');if(v){v.srcObject=null;v.style.display='none';}let f=document.getElementById('liveFrameImg');if(f)f.remove();document.getElementById('livePlaceholder').style.display='flex';document.getElementById('liveControlsCard').style.display='none';document.getElementById('liveStatus').style.display='none';document.getElementById('liveDuration').textContent='00:00:00';await db.collection('lives').doc('live_atual').update({ativa:!1});carregarLiveTela();}
async function finalizarLive(){if(!confirm('Finalizar live?'))return;await pararLive();mostrarToast('✅ Finalizada!','info');}

// LIVE - GRAVAÇÃO / EFEITOS / TELAS
function iniciarGravacaoTrecho(){if(!liveStream||gravandoTrecho)return;try{mediaRecorder=new MediaRecorder(liveStream,MediaRecorder.isTypeSupported('video/webm')?{mimeType:'video/webm'}:{});}catch(e){mediaRecorder=new MediaRecorder(liveStream);}recordedChunks=[];mediaRecorder.ondataavailable=e=>{if(e.data.size>0)recordedChunks.push(e.data);};mediaRecorder.onstop=()=>{let blob=new Blob(recordedChunks,{type:'video/webm'}),url=URL.createObjectURL(blob);trechosGravados.push({id:Date.now(),url,blob});mostrarToast('✅ Trecho salvo!','success');};mediaRecorder.start(1000);gravandoTrecho=!0;document.getElementById('btnRecordClip').style.display='none';document.getElementById('btnStopClip').style.display='inline-block';mostrarToast('⏺️ Gravando...','info');}
function pararGravacaoTrecho(){if(!gravandoTrecho||!mediaRecorder)return;mediaRecorder.stop();gravandoTrecho=!1;document.getElementById('btnRecordClip').style.display='inline-block';document.getElementById('btnStopClip').style.display='none';}
function salvarTrechosLive(){trechosGravados.forEach((c,i)=>{let a=document.createElement('a');a.href=c.url;a.download='clip-'+(i+1)+'.webm';a.click();});mostrarToast('💾 '+trechosGravados.length+' trechos!','success');}
async function trocarCameraLive(){liveFacingMode=liveFacingMode==='user'?'environment':'user';if(liveStreamLocal)liveStreamLocal.getTracks().forEach(t=>t.stop());try{let s=await navigator.mediaDevices.getUserMedia({video:{facingMode:liveFacingMode,width:{ideal:640}},audio:!0});liveStreamLocal=s;liveStream=s;document.getElementById('liveVideo').srcObject=s;mostrarToast('🔄 Câmera '+(liveFacingMode==='user'?'Frontal':'Traseira'),'info');}catch(e){}}
function aplicarEfeitoLive(efeito){let v=document.getElementById('liveVideo');if(!v)return;v.style.filter='';efeitoLiveAtual=efeito;if(efeito==='bw')v.style.filter='grayscale(100%)';else if(efeito==='sepia')v.style.filter='sepia(80%)';else if(efeito==='neon')v.style.filter='brightness(1.2) contrast(1.3) saturate(1.5)';else if(efeito==='warm')v.style.filter='sepia(20%) saturate(1.3)';mostrarToast('✨ Efeito: '+efeito,'info');}
function mostrarTelaLive(tipo){document.getElementById('overlayComercial').style.display='none';document.getElementById('overlayAnuncio').style.display='none';if(tipo==='comercial')document.getElementById('overlayComercial').style.display='block';else if(tipo==='anuncio')document.getElementById('overlayAnuncio').style.display='flex';}
function carregarComercialLive(event){let f=event.target.files[0];if(!f)return;let v=document.getElementById('comercialVideo');v.src=URL.createObjectURL(f);v.loop=!0;v.muted=!0;mostrarToast('🎬 Comercial carregado!','success');}
async function notificarClientesWhatsApp(){if(!barbeiroLogado)return;try{let sn=await db.collection('clientes').get();let url=window.location.href.split('?')[0]+'?live=1';let c=0;sn.forEach(async(doc)=>{let cl=doc.data();if(cl.celular&&cl.celular.length>=10){let n=cl.celular.replace(/\D/g,'');if(n.length===11)n='55'+n;await db.collection('notificacoes').add({clienteId:cl.id,tipo:'whatsapp',link:'https://wa.me/'+n+'?text='+encodeURIComponent('🔴 LIVE! '+url),lida:!1,data:new Date().toISOString()});c++;}});setTimeout(()=>{let el=document.getElementById('whatsappStatus');if(el){el.textContent='✅ '+c+' links gerados!';el.style.color='#00cc66';}},2000);}catch(e){}}
async function enviarConvitesWhatsApp(){if(!barbeiroLogado)return;if(!confirm('Abrir WhatsApp para todos?'))return;try{let sn=await db.collection('clientes').get();let url=window.location.href.split('?')[0]+'?live=1';let c=0;for(let doc of sn.docs){let cl=doc.data();if(cl.celular&&cl.celular.length>=10){let n=cl.celular.replace(/\D/g,'');if(n.length===11)n='55'+n;if(c<5)window.open('https://wa.me/'+n+'?text='+encodeURIComponent('🔴 LIVE! '+url),'_blank');c++;await new Promise(r=>setTimeout(r,300));}}mostrarToast('📱 '+c+' convites!','success');}catch(e){}}
function carregarAnuncioAuto(event){let f=event.target.files[0];if(!f)return;let r=new FileReader();r.onload=e=>{anuncioImagemAuto=e.target.result;let el=document.getElementById('anuncioAutoStatus');if(el){el.textContent='✅ Imagem carregada!';el.style.color='#00cc66';}};r.readAsDataURL(f);}
function iniciarAnuncioAutomatico(){if(!anuncioImagemAuto)return;let t=document.getElementById('anuncioTextoInput').value.trim();let i=parseInt(document.getElementById('anuncioIntervalo').value)*1000;anuncioTextoAuto=t||'🔥 Oferta!';anuncioAutoAtivo=!0;document.getElementById('btnIniciarAnuncioAuto').style.display='none';document.getElementById('btnPararAnuncioAuto').style.display='inline-block';let el=document.getElementById('anuncioAutoStatus');if(el){el.textContent='▶️ Ativo - '+i/1000+'s';el.style.color='#FFD700';}mostrarAnuncioAuto();anuncioAutoInterval=setInterval(mostrarAnuncioAuto,i);}
function mostrarAnuncioAuto(){let o=document.getElementById('overlayAnuncio'),img=document.getElementById('anuncioImg'),txt=document.getElementById('anuncioTexto');if(!o||!img)return;img.src=anuncioImagemAuto;img.classList.add('anuncio-ativo');txt.textContent=anuncioTextoAuto;o.style.display='flex';o.style.opacity='1';if(anuncioAutoTimeout)clearTimeout(anuncioAutoTimeout);anuncioAutoTimeout=setTimeout(esconderAnuncioAuto,5000);}
function esconderAnuncioAuto(){let o=document.getElementById('overlayAnuncio');if(!o)return;o.style.opacity='0';setTimeout(()=>{o.style.display='none';},400);}
function fecharAnuncioManual(){esconderAnuncioAuto();}
function pararAnuncioAutomatico(){anuncioAutoAtivo=!1;if(anuncioAutoInterval)clearInterval(anuncioAutoInterval);if(anuncioAutoTimeout)clearTimeout(anuncioAutoTimeout);esconderAnuncioAuto();document.getElementById('btnIniciarAnuncioAuto').style.display='inline-block';document.getElementById('btnPararAnuncioAuto').style.display='none';let el=document.getElementById('anuncioAutoStatus');if(el){el.textContent='⏹️ Parado';el.style.color='#aaa';}}
async function curtirLive(){try{await db.collection('lives').doc('live_atual').update({likes:firebase.firestore.FieldValue.increment(1)});let h=document.createElement('div');h.textContent='❤️';h.style.cssText='position:absolute;font-size:30px;pointer-events:none;z-index:20;animation:floatHeart 2s ease-out forwards;left:'+(Math.random()*80+10)+'%;bottom:20%;';document.getElementById('livePlayerContainer').appendChild(h);setTimeout(()=>h.remove(),2000);}catch(e){}}
async function reagirLive(emoji){try{let r=document.createElement('div');r.textContent=emoji;r.style.cssText='position:absolute;font-size:35px;pointer-events:none;z-index:20;animation:floatReaction 3s ease-out forwards;left:'+(Math.random()*80+10)+'%;bottom:30%;';document.getElementById('livePlayerContainer').appendChild(r);setTimeout(()=>r.remove(),3000);}catch(e){}}
function compartilharLive(rede){let url=window.location.href,t='🔴 Clube do Barbeiro - Ao Vivo!';if(rede==='link'){navigator.clipboard.writeText(url);mostrarToast('📋 Link copiado!','success');}else if(rede==='whatsapp')window.open('https://wa.me/?text='+encodeURIComponent(t+' '+url),'_blank');}
async function iniciarGravacaoAudio(){if(gravandoAudio)return;try{let s=await navigator.mediaDevices.getUserMedia({audio:!0});mediaRecorderAudio=new MediaRecorder(s);audioChunks=[];mediaRecorderAudio.ondataavailable=(e)=>{if(e.data.size>0)audioChunks.push(e.data);};mediaRecorderAudio.onstop=async()=>{let blob=new Blob(audioChunks,{type:'audio/webm'});let reader=new FileReader();reader.onload=async(e)=>{let nome=clienteLogado?clienteLogado.nome:(barbeiroLogado?barbeiroLogado.nome:'Visitante');await db.collection('lives').doc('live_atual').update({chat:firebase.firestore.FieldValue.arrayUnion({autor:nome,audio:e.target.result,data:new Date().toISOString()})});};reader.readAsDataURL(blob);s.getTracks().forEach(t=>t.stop());};mediaRecorderAudio.start();gravandoAudio=!0;let btn=document.getElementById('btnMic');if(btn){btn.classList.add('recording');btn.textContent='⏹️';}mostrarToast('🎤 Gravando...','info');setTimeout(()=>{if(gravandoAudio)pararGravacaoAudio();},30000);}catch(e){mostrarToast('❌ Permita o microfone!','error');}}
function pararGravacaoAudio(){if(!gravandoAudio||!mediaRecorderAudio)return;mediaRecorderAudio.stop();gravandoAudio=!1;let btn=document.getElementById('btnMic');if(btn){btn.classList.remove('recording');btn.textContent='🎤';}mostrarToast('✅ Áudio enviado!','success');}

