async function carregarMensagensChat(cid){let c=document.getElementById('chatMensagens');if(!c)return;let meuId=clienteLogado?clienteLogado.id:(barbeiroLogado?barbeiroLogado.id:'');let chatId=[meuId,cid].sort().join('_');try{let doc=await db.collection('chats').doc(chatId).get();let msgs=doc.exists?(doc.data().mensagens||[]):[];if(msgs.length===0){c.innerHTML='<div style="text-align:center;color:#aaa;padding:20px;">💬 Nenhuma mensagem</div>';return;}let html='',lastDate='';msgs.forEach(m=>{let msgDate=new Date(m.data).toLocaleDateString('pt-BR');if(msgDate!==lastDate){html+='<div style="text-align:center;margin:10px 0;"><span style="background:#1a1a1a;color:#aaa;padding:4px 12px;border-radius:10px;font-size:11px;">'+msgDate+'</span></div>';lastDate=msgDate;}let isSent=m.autorId===meuId;let time=new Date(m.data).toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'});if(isSent){html+='<div style="display:flex;justify-content:flex-end;margin:3px 0;"><div style="max-width:75%;background:linear-gradient(135deg,#D4A84B,#B8923A);color:#1a1a1a;padding:8px 12px;border-radius:12px 12px 0 12px;font-size:13px;">'+m.texto+'<div style="text-align:right;font-size:9px;opacity:0.7;margin-top:2px;">'+time+'</div></div></div>';}else{html+='<div style="display:flex;justify-content:flex-start;margin:3px 0;"><div style="max-width:75%;background:#2a2a2a;color:#fff;padding:8px 12px;border-radius:12px 12px 12px 0;font-size:13px;"><div style="font-size:10px;color:#D4A84B;font-weight:600;margin-bottom:2px;">'+m.autor+'</div>'+m.texto+'<div style="text-align:right;font-size:9px;opacity:0.5;margin-top:2px;">'+time+'</div></div></div>';}});c.innerHTML=html;c.scrollTop=c.scrollHeight;}catch(e){}}
async function enviarMensagemChat(){let i=document.getElementById('chatMensagemInput');if(!i)return;let t=i.value.trim();if(!t)return;let cid=document.getElementById('chatClienteId').value;let meuId=clienteLogado?clienteLogado.id:(barbeiroLogado?barbeiroLogado.id:'');let meuNome=clienteLogado?clienteLogado.nome:(barbeiroLogado?barbeiroLogado.nome:'Anônimo');let chatId=[meuId,cid].sort().join('_');let doc=await db.collection('chats').doc(chatId).get();let msgs=doc.exists?(doc.data().mensagens||[]):[];msgs.push({autor:meuNome,autorId:meuId,texto:t,data:new Date().toISOString()});await db.collection('chats').doc(chatId).set({mensagens:msgs});i.value='';carregarMensagensChat(cid);}
